from flask import Flask, request, jsonify
import random
import string

app = Flask(__name__)

auth_codes = {}

def generate_auth_code(user_id):
    code = ''.join(random.choices(string.ascii_letters + string.digits, k=16))
    auth_codes[code] = user_id
    return code

@app.route('/authorize', methods=['POST'])
def authorize():
    user_id = request.json.get('user_id')
    if user_id:
        code = generate_auth_code(user_id)
        return jsonify({'authorization_code': code}), 200
    return jsonify({'error': 'Invalid request'}), 400

@app.route('/token', methods=['POST'])
def token():
    code = request.json.get('authorization_code')
    if code in auth_codes:
        user_id = auth_codes[code]
        return jsonify({'access_token': f'token_for_{user_id}'}), 200
    return jsonify({'error': 'Invalid authorization code'}), 400

if __name__ == '__main__':
    app.run(debug=True)